INSERT INTO exercises (id, name, muscle_group, primary_muscle, secondary_muscles, instructions, form_tips, common_mistakes, image_url) VALUES
('ex-1', 'Bench Press', 'Chest', 'Pectoralis Major', ARRAY['Triceps', 'Anterior Deltoids'], ARRAY['Lie flat on the bench with your feet flat on the floor.', 'Grip the barbell slightly wider than shoulder-width.', 'Unrack the bar and lower it slowly to your mid-chest.', 'Push the bar back up powerfully while keeping your elbows tucked at a 45-degree angle.'], ARRAY['Keep your shoulder blades retracted and depressed throughout the lift.', 'Drive your feet into the floor to stay tight and stable.', 'Avoid bouncing the bar off your chest.'], '{}'::text[], 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?q=80&w=600'),
('ex-2', 'Barbell Squat', 'Legs', 'Quadriceps', ARRAY['Glutes', 'Hamstrings'], ARRAY['Position the bar on your upper back and stand with feet shoulder-width apart.', 'Brace your core and bend your knees and hips to lower down.', 'Descend until your thighs are at least parallel to the floor.', 'Drive through your heels to return to standing.'], ARRAY['Keep your chest up and back flat throughout the movement.', 'Track your knees in line with your toes.', 'Avoid letting your heels lift off the floor.'], '{}'::text[], 'https://images.unsplash.com/photo-1574680096145-d05b474e2155?q=80&w=600'),
('ex-3', 'Deadlift', 'Back', 'Erector Spinae', ARRAY['Glutes', 'Hamstrings', 'Traps'], ARRAY['Stand with feet hip-width apart, bar over mid-foot.', 'Hinge at the hips and grip the bar just outside your knees.', 'Keep your back flat and chest up as you drive through your heels to stand.', 'Lower the bar back down with control by hinging at the hips first.'], ARRAY['Keep the bar close to your shins and thighs throughout the lift.', 'Brace your core hard before initiating the pull.', 'Avoid rounding your lower back.'], '{}'::text[], 'https://images.unsplash.com/photo-1603287638312-c001b929411f?q=80&w=600'),
('ex-4', 'Overhead Press', 'Shoulders', 'Anterior Deltoids', ARRAY['Triceps', 'Upper Chest'], ARRAY['Stand with feet shoulder-width apart, bar racked at shoulder height.', 'Brace your core and press the bar straight overhead.', 'Fully lock out your arms at the top.', 'Lower the bar back down to shoulder level with control.'], ARRAY['Avoid arching your lower back excessively.', 'Keep your glutes and core tight throughout the press.', 'Move your head slightly back as the bar passes your face.'], '{}'::text[], 'https://images.unsplash.com/photo-1532029837206-abbe2b7620e3?q=80&w=600'),
('ex-5', 'Pull-Up', 'Back', 'Latissimus Dorsi', ARRAY['Biceps', 'Rear Deltoids'], ARRAY['Hang from a bar with an overhand grip, slightly wider than shoulders.', 'Pull your body up until your chin clears the bar.', 'Focus on driving your elbows down and back.', 'Lower yourself back down with control to a full hang.'], ARRAY['Avoid excessive swinging or kipping.', 'Initiate the pull by depressing your shoulder blades first.', 'Fully extend your arms at the bottom of each rep.'], '{}'::text[], 'https://images.unsplash.com/photo-1603287638312-c001b929411f?q=80&w=600'),
('ex-6', 'Bent-Over Barbell Row', 'Back', 'Latissimus Dorsi', ARRAY['Rhomboids', 'Biceps', 'Rear Deltoids'], ARRAY['Hinge at the hips with a flat back, holding the bar with an overhand grip.', 'Let the bar hang at arm''s length below your shoulders.', 'Pull the bar toward your lower ribcage, squeezing your shoulder blades.', 'Lower the bar back down with control.'], ARRAY['Keep your torso angle fixed throughout the set.', 'Avoid using momentum or jerking the weight up.', 'Keep your neck neutral, not looking up.'], '{}'::text[], 'https://images.unsplash.com/photo-1603287638312-c001b929411f?q=80&w=600'),
('ex-7', 'Walking Lunge', 'Legs', 'Quadriceps', ARRAY['Glutes', 'Hamstrings'], ARRAY['Stand tall holding dumbbells at your sides.', 'Step forward with one leg and lower your hips until both knees are bent 90 degrees.', 'Push through your front heel to step forward into the next lunge.', 'Continue alternating legs as you move forward.'], ARRAY['Keep your torso upright throughout each step.', 'Avoid letting your front knee travel past your toes.', 'Take controlled, deliberate steps rather than rushing.'], '{}'::text[], 'https://images.unsplash.com/photo-1574680096145-d05b474e2155?q=80&w=600'),
('ex-8', 'Plank', 'Abs', 'Rectus Abdominis', ARRAY['Obliques', 'Lower Back'], ARRAY['Get into a forearm plank position with elbows under your shoulders.', 'Keep your body in a straight line from head to heels.', 'Brace your core and hold the position.', 'Breathe steadily while maintaining the hold.'], ARRAY['Avoid letting your hips sag or pike up.', 'Squeeze your glutes to help stabilize your lower back.', 'Keep your neck neutral, looking at the floor.'], '{}'::text[], 'https://images.unsplash.com/photo-1517838277536-f5f99be501cd?q=80&w=600'),
('ex-9', 'Barbell Curl', 'Biceps', 'Biceps Brachii', ARRAY['Forearms'], ARRAY['Stand holding a barbell with an underhand, shoulder-width grip.', 'Keep your elbows pinned to your sides.', 'Curl the bar up toward your shoulders.', 'Lower it back down slowly to full extension.'], ARRAY['Avoid swinging your torso to generate momentum.', 'Keep your wrists straight throughout the curl.', 'Squeeze the biceps at the top of the movement.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-10', 'Bench Dip', 'Triceps', 'Triceps Brachii', ARRAY['Anterior Deltoids'], ARRAY['Sit on the edge of a bench with hands gripping the edge beside your hips.', 'Walk your feet forward and lower your body by bending your elbows.', 'Lower until your upper arms are roughly parallel to the floor.', 'Push back up to the starting position.'], ARRAY['Keep your elbows pointing backward, not out to the sides.', 'Don''t let your shoulders shrug up toward your ears.', 'Add weight on your lap for extra resistance once bodyweight gets easy.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-11', 'Leg Press', 'Legs', 'Quadriceps', ARRAY['Glutes', 'Hamstrings'], ARRAY['Sit in the leg press machine with feet shoulder-width apart on the platform.', 'Lower the platform by bending your knees toward your chest.', 'Stop when your knees reach about a 90-degree angle.', 'Push through your heels to extend your legs back out.'], ARRAY['Avoid locking your knees completely at the top.', 'Keep your lower back pressed against the seat.', 'Don''t let your knees cave inward during the press.'], '{}'::text[], 'https://images.unsplash.com/photo-1574680096145-d05b474e2155?q=80&w=600'),
('ex-12', 'Lat Pulldown', 'Back', 'Latissimus Dorsi', ARRAY['Biceps', 'Rhomboids'], ARRAY['Sit at the machine and grip the bar wider than shoulder-width.', 'Lean back slightly and pull the bar down to your upper chest.', 'Squeeze your shoulder blades together at the bottom.', 'Slowly release the bar back to the starting position.'], ARRAY['Avoid pulling with your arms alone; drive with your lats.', 'Don''t lean back excessively to cheat the weight down.', 'Keep your chest up throughout the movement.'], '{}'::text[], 'https://images.unsplash.com/photo-1603287638312-c001b929411f?q=80&w=600'),
('ex-13', 'Push-Up', 'Chest', 'Pectoralis Major', ARRAY['Triceps', 'Core'], ARRAY['Start in a plank position with hands slightly wider than shoulders.', 'Keep your body in a straight line from head to heels.', 'Lower your chest toward the floor by bending your elbows.', 'Push back up to the starting position.'], ARRAY['Keep your core braced to prevent hips from sagging.', 'Lower until your chest is a few inches from the floor.', 'Exhale as you push up.'], '{}'::text[], 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?q=80&w=600'),
('ex-14', 'Romanian Deadlift', 'Legs', 'Hamstrings', ARRAY['Glutes', 'Lower Back'], ARRAY['Hold a barbell in front of your thighs with a shoulder-width grip.', 'Push your hips back while keeping a slight bend in your knees.', 'Lower the bar along your legs until you feel a hamstring stretch.', 'Drive your hips forward to return to standing.'], ARRAY['Keep the bar close to your legs throughout the movement.', 'Maintain a flat back and avoid rounding your spine.', 'Stop the descent once you feel a deep hamstring stretch.'], '{}'::text[], 'https://images.unsplash.com/photo-1574680096145-d05b474e2155?q=80&w=600'),
('ex-15', 'Arnold Press', 'Shoulders', 'Anterior & Lateral Deltoids', ARRAY['Triceps'], ARRAY['Sit holding dumbbells in front of your shoulders, palms facing you.', 'Press the dumbbells overhead while rotating your palms to face forward.', 'Fully extend your arms at the top.', 'Reverse the rotation as you lower back to the start.'], ARRAY['Control the rotation smoothly rather than rushing it.', 'Keep your core braced to avoid excessive back arch.', 'Don''t let the dumbbells drift forward or behind your head.'], '{}'::text[], 'https://images.unsplash.com/photo-1532029837206-abbe2b7620e3?q=80&w=600'),
('ex-16', 'Incline Dumbbell Press', 'Chest', 'Upper Pectoralis Major', ARRAY['Anterior Deltoids', 'Triceps'], ARRAY['Set the bench to a 30-45 degree incline.', 'Hold a dumbbell in each hand at shoulder level, palms facing forward.', 'Press the dumbbells up until your arms are extended.', 'Lower slowly back to the starting position with control.'], ARRAY['Don''t let the incline exceed 45 degrees or shoulders take over.', 'Keep wrists straight and stacked over elbows.', 'Squeeze your chest at the top of each rep.'], '{}'::text[], 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?q=80&w=600'),
('ex-17', 'Cable Chest Fly', 'Chest', 'Pectoralis Major', ARRAY['Anterior Deltoids'], ARRAY['Stand centered between two cable stacks with handles set at chest height.', 'Step forward with a slight bend in your elbows.', 'Bring your hands together in front of your chest in an arcing motion.', 'Slowly return to the starting position, feeling a stretch across the chest.'], ARRAY['Keep a slight, fixed bend in the elbows throughout.', 'Focus on squeezing the chest rather than pulling with the arms.', 'Avoid letting the weights slam at the stretch position.'], '{}'::text[], 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?q=80&w=600'),
('ex-18', 'Dips (Chest Focus)', 'Chest', 'Lower Pectoralis Major', ARRAY['Triceps', 'Anterior Deltoids'], ARRAY['Grip the parallel bars and support your body with arms extended.', 'Lean your torso forward and bend your knees.', 'Lower your body until your shoulders are below your elbows.', 'Push back up to the starting position.'], ARRAY['Leaning forward shifts emphasis onto the chest.', 'Avoid flaring elbows out too wide to protect the shoulders.', 'Control the descent instead of dropping quickly.'], '{}'::text[], 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?q=80&w=600'),
('ex-19', 'Seated Cable Row', 'Back', 'Middle Back (Rhomboids)', ARRAY['Latissimus Dorsi', 'Biceps'], ARRAY['Sit with knees slightly bent, gripping the handle with arms extended.', 'Keep your back straight and pull the handle toward your torso.', 'Squeeze your shoulder blades together at the end of the pull.', 'Extend your arms back out with control.'], ARRAY['Avoid rounding your back or using excessive body swing.', 'Keep your elbows close to your body during the pull.', 'Pause briefly at full contraction for better activation.'], '{}'::text[], 'https://images.unsplash.com/photo-1603287638312-c001b929411f?q=80&w=600'),
('ex-20', 'Lateral Raise', 'Shoulders', 'Lateral Deltoids', ARRAY['Traps'], ARRAY['Stand holding a dumbbell in each hand at your sides.', 'Raise your arms out to the sides until they reach shoulder height.', 'Keep a slight bend in your elbows throughout.', 'Lower the dumbbells back down slowly.'], ARRAY['Avoid using momentum or swinging the weights up.', 'Lead with your elbows, not your hands.', 'Stop at shoulder height to keep tension on the delts.'], '{}'::text[], 'https://images.unsplash.com/photo-1532029837206-abbe2b7620e3?q=80&w=600'),
('ex-21', 'Face Pull', 'Shoulders', 'Rear Deltoids', ARRAY['Rhomboids', 'Rotator Cuff'], ARRAY['Set a cable pulley to face height with a rope attachment.', 'Pull the rope toward your face, splitting it apart at the end.', 'Keep your elbows high and in line with your shoulders.', 'Slowly return to the starting position.'], ARRAY['Focus on squeezing your rear delts, not your traps.', 'Keep your torso upright throughout the movement.', 'Use a lighter weight to prioritize form over load.'], '{}'::text[], 'https://images.unsplash.com/photo-1532029837206-abbe2b7620e3?q=80&w=600'),
('ex-22', 'Upright Row', 'Shoulders', 'Lateral Deltoids', ARRAY['Traps', 'Biceps'], ARRAY['Hold a barbell or dumbbells in front of your thighs.', 'Pull the weight straight up toward your chin, leading with your elbows.', 'Raise until your elbows reach shoulder height.', 'Lower back down with control.'], ARRAY['Keep the bar close to your body throughout the pull.', 'Avoid raising it above shoulder height to protect the shoulder joint.', 'Use a moderate grip width to reduce joint strain.'], '{}'::text[], 'https://images.unsplash.com/photo-1532029837206-abbe2b7620e3?q=80&w=600'),
('ex-23', 'Dumbbell Hammer Curl', 'Biceps', 'Brachialis', ARRAY['Biceps Brachii', 'Forearms'], ARRAY['Hold a dumbbell in each hand with palms facing your body.', 'Curl the weights up while keeping your palms neutral.', 'Bring the dumbbells up to shoulder level.', 'Lower back down with control.'], ARRAY['Keep your elbows stationary throughout the movement.', 'Avoid rotating your wrists during the curl.', 'Move at a controlled tempo to maximize tension.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-24', 'Concentration Curl', 'Biceps', 'Biceps Brachii', ARRAY['Forearms'], ARRAY['Sit on a bench and brace your elbow against your inner thigh.', 'Hold a dumbbell with your arm fully extended.', 'Curl the weight up toward your shoulder.', 'Lower it back down slowly with full control.'], ARRAY['Keep your upper arm completely still throughout.', 'Focus on a strong peak contraction at the top.', 'Avoid using your shoulder to assist the lift.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-25', 'Preacher Curl', 'Biceps', 'Biceps Brachii', ARRAY['Forearms'], ARRAY['Sit at a preacher bench with your upper arms resting on the pad.', 'Hold the bar or dumbbells with an underhand grip.', 'Curl the weight up toward your shoulders.', 'Lower back down slowly without fully relaxing at the bottom.'], ARRAY['Avoid locking out and relaxing completely at the bottom.', 'Keep your movements slow and controlled to reduce elbow strain.', 'Don''t let your shoulders round forward during the curl.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-26', 'Cable Curl', 'Biceps', 'Biceps Brachii', ARRAY['Forearms'], ARRAY['Stand facing a low cable pulley with a straight or EZ bar attached.', 'Hold the bar with an underhand grip, arms extended.', 'Curl the bar up toward your shoulders.', 'Lower back down under control, maintaining tension.'], ARRAY['Keep constant tension on the biceps throughout the set.', 'Avoid leaning back to help lift the weight.', 'Keep elbows close to your torso.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-27', 'Close-Grip Bench Press', 'Triceps', 'Triceps Brachii', ARRAY['Pectoralis Major', 'Anterior Deltoids'], ARRAY['Lie on a bench and grip the bar with hands shoulder-width apart.', 'Lower the bar to your lower chest, keeping elbows tucked.', 'Press the bar back up, focusing on triceps extension.', 'Lock out your arms at the top.'], ARRAY['Keep your elbows close to your body throughout the press.', 'Avoid flaring elbows out to protect your shoulders.', 'Control the bar on the way down.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-28', 'Tricep Pushdown', 'Triceps', 'Triceps Brachii', '{}'::text[], ARRAY['Stand facing a high cable pulley with a straight or rope attachment.', 'Keep your elbows pinned to your sides.', 'Push the attachment down until your arms are fully extended.', 'Slowly return to the starting position.'], ARRAY['Avoid letting your elbows drift away from your body.', 'Keep your torso upright and avoid leaning into the movement.', 'Fully extend at the bottom for maximum contraction.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-29', 'Overhead Tricep Extension', 'Triceps', 'Triceps Brachii (Long Head)', '{}'::text[], ARRAY['Hold a dumbbell with both hands overhead, arms fully extended.', 'Lower the weight behind your head by bending your elbows.', 'Keep your upper arms stationary and close to your ears.', 'Extend back up to the starting position.'], ARRAY['Avoid flaring your elbows out to the sides.', 'Keep your core braced to protect your lower back.', 'Use a controlled tempo to avoid shoulder strain.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-30', 'Skull Crusher', 'Triceps', 'Triceps Brachii', '{}'::text[], ARRAY['Lie on a bench holding an EZ bar with arms extended above your chest.', 'Bend your elbows to lower the bar toward your forehead.', 'Keep your upper arms stationary throughout.', 'Extend your arms back up to the starting position.'], ARRAY['Keep your elbows pointed forward, not flared out.', 'Lower the bar slowly to avoid hitting your head.', 'Avoid moving your upper arms during the rep.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-31', 'Standing Calf Raise', 'Legs', 'Gastrocnemius', ARRAY['Soleus'], ARRAY['Stand on a raised platform with your heels hanging off the edge.', 'Lower your heels below the platform to feel a calf stretch.', 'Rise up onto your toes as high as possible.', 'Lower back down slowly with control.'], ARRAY['Pause briefly at the top for a strong contraction.', 'Avoid bouncing at the bottom of the movement.', 'Use a full range of motion for best results.'], '{}'::text[], 'https://images.unsplash.com/photo-1574680096145-d05b474e2155?q=80&w=600'),
('ex-32', 'Hanging Leg Raise', 'Abs', 'Lower Rectus Abdominis', ARRAY['Hip Flexors'], ARRAY['Hang from a pull-up bar with arms fully extended.', 'Keep your legs straight and raise them until parallel to the floor.', 'Lower your legs back down slowly with control.', 'Avoid swinging your body during the movement.'], ARRAY['Engage your core before initiating the raise.', 'Avoid using momentum to swing your legs up.', 'Control the descent instead of dropping quickly.'], '{}'::text[], 'https://images.unsplash.com/photo-1517838277536-f5f99be501cd?q=80&w=600'),
('ex-33', 'Cable Crunch', 'Abs', 'Rectus Abdominis', ARRAY['Obliques'], ARRAY['Kneel below a high cable pulley holding a rope attachment near your head.', 'Crunch your torso down, bringing your elbows toward your knees.', 'Focus on rounding your spine rather than bending at the hips.', 'Slowly return to the starting position.'], ARRAY['Keep your hips stationary throughout the crunch.', 'Focus on contracting your abs, not pulling with your arms.', 'Use a moderate weight to maintain proper form.'], '{}'::text[], 'https://images.unsplash.com/photo-1517838277536-f5f99be501cd?q=80&w=600'),
('ex-34', 'Russian Twist', 'Abs', 'Obliques', ARRAY['Rectus Abdominis'], ARRAY['Sit on the floor with your knees bent and lean back slightly.', 'Hold a weight with both hands in front of your chest.', 'Rotate your torso to bring the weight to one side of your hips.', 'Rotate back through center to the opposite side.'], ARRAY['Keep your chest up and avoid rounding your back.', 'Move with control rather than twisting quickly.', 'Lift your feet off the floor for an added challenge.'], '{}'::text[], 'https://images.unsplash.com/photo-1517838277536-f5f99be501cd?q=80&w=600'),
('ex-35', 'Bicycle Crunch', 'Abs', 'Rectus Abdominis', ARRAY['Obliques'], ARRAY['Lie on your back with hands behind your head and knees bent.', 'Bring one knee toward your chest while rotating the opposite elbow to meet it.', 'Extend the other leg out straight as you rotate.', 'Alternate sides in a smooth pedaling motion.'], ARRAY['Avoid pulling on your neck with your hands.', 'Keep the movement slow and controlled rather than rushed.', 'Exhale as you crunch toward each knee.'], '{}'::text[], 'https://images.unsplash.com/photo-1517838277536-f5f99be501cd?q=80&w=600'),
('ex-36', 'Wrist Curl', 'Forearms', 'Wrist Flexors', '{}'::text[], ARRAY['Sit and rest your forearms on your thighs, palms facing up, holding a barbell.', 'Let your wrists hang off your knees.', 'Curl the bar up by flexing your wrists.', 'Lower back down slowly to full stretch.'], ARRAY['Keep your forearms stationary throughout the movement.', 'Use a light weight and focus on full range of motion.', 'Avoid using your arms or shoulders to assist the curl.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-37', 'Reverse Wrist Curl', 'Forearms', 'Wrist Extensors', '{}'::text[], ARRAY['Rest your forearms on your thighs with palms facing down, holding a barbell.', 'Let your wrists hang off your knees.', 'Extend your wrists to lift the bar upward.', 'Lower back down slowly with control.'], ARRAY['Use a lighter weight than standard wrist curls.', 'Keep the movement slow to avoid straining the wrist joint.', 'Maintain full forearm contact with your thighs.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-38', 'Farmer''s Carry', 'Forearms', 'Forearm Flexors (Grip)', ARRAY['Traps', 'Core'], ARRAY['Hold a heavy dumbbell or kettlebell in each hand at your sides.', 'Stand tall with shoulders back and core braced.', 'Walk forward for a set distance or time.', 'Set the weights down with control at the end.'], ARRAY['Keep your shoulders pulled back, not shrugged up.', 'Take controlled, steady steps rather than rushing.', 'Grip the handles as hard as possible throughout the carry.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-39', 'Dead Hang', 'Forearms', 'Forearm Flexors (Grip)', ARRAY['Latissimus Dorsi'], ARRAY['Grip a pull-up bar with hands shoulder-width apart.', 'Hang with your arms fully extended and feet off the floor.', 'Keep your shoulders slightly engaged, not fully relaxed.', 'Hold the position for the desired duration.'], ARRAY['Avoid swinging your body during the hold.', 'Breathe steadily rather than holding your breath.', 'Build up hang time gradually to avoid grip fatigue injuries.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-40', 'Plate Pinch Hold', 'Forearms', 'Forearm Flexors (Grip)', '{}'::text[], ARRAY['Pinch two weight plates together, smooth sides facing out.', 'Hold the plates at your sides with straight arms.', 'Maintain the pinch grip for the desired duration.', 'Set the plates down with control when finished.'], ARRAY['Keep your wrists straight, not bent, during the hold.', 'Start with lighter plates to build up grip strength safely.', 'Avoid letting your shoulders shrug up during the hold.'], '{}'::text[], 'https://images.unsplash.com/photo-1581009146145-b5ef050c2e1e?q=80&w=600'),
('ex-hip-thrust', 'Hip Thrust', 'Glutes', 'Gluteus Maximus', ARRAY['Hamstrings', 'Core'], ARRAY['Sit on the floor with your upper back resting against a sturdy bench.', 'Roll a barbell over your hips, using a pad for comfort.', 'Place feet flat on the floor, hip-width apart.', 'Drive through your heels to lift your hips until thighs are parallel to floor.', 'Squeeze glutes at lockout, then lower hips back down.'], ARRAY['Keep your chin tucked and look forward, not up at the ceiling.', 'Ensure shins are vertical at the top of the lift.'], ARRAY['Hyperextending the lower back at the top.', 'Pushing through the toes instead of the heels.'], 'https://images.unsplash.com/photo-1574680096145-d05b474e2155?q=80&w=600'),
('ex-calf-raise', 'Calf Raise', 'Calves', 'Gastrocnemius', ARRAY['Soleus'], ARRAY['Stand with the balls of your feet on an elevated step or block.', 'Hold onto a support for balance if needed.', 'Lower your heels below the step level to feel a stretch.', 'Push up high onto your toes, contracting the calves.', 'Hold the contraction for a second, then lower slowly.'], ARRAY['Keep your knees straight but not completely locked out.', 'Pause at the bottom stretch and top contraction.'], ARRAY['Bouncing quickly at the bottom using Achilles tendon elasticity.', 'Not using a full range of motion.'], 'https://images.unsplash.com/photo-1574680096145-d05b474e2155?q=80&w=600')
